logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO").upper())

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_PREFIX = os.getenv("OUTPUT_PREFIX", "processed/")
SNS_TOPIC_ARN = os.getenv("SNS_TOPIC_ARN", "")
DEFAULT_OUTPUT_BUCKET = os.getenv("OUTPUT_BUCKET", "")


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    records = event.get("Records", [])
    results = []

    for record in records:
        try:
            bucket, key = extract_s3_info(record)
            if not bucket or not key:
                logger.warning("Skipping record without valid S3 info: %s", json.dumps(record))
                continue

            logger.info("Processing object s3://%s/%s", bucket, key)

            image_bytes, metadata = read_s3_object(bucket, key)
            processed_bytes = process_image(image_bytes)

            output_bucket = DEFAULT_OUTPUT_BUCKET or bucket
            output_key = build_output_key(key)

            write_s3_object(
                bucket=output_bucket,
                key=output_key,
                body=processed_bytes,
                source_bucket=bucket,
                source_key=key,
                source_metadata=metadata,
            )

            message = {
                "status": "SUCCESS",
                "input_bucket": bucket,
                "input_key": key,
                "output_bucket": output_bucket,
                "output_key": output_key,
                "request_id": getattr(context, "aws_request_id", None),
            }

            publish_notification("Image processed successfully", message)
            logger.info("Successfully processed s3://%s/%s -> s3://%s/%s", bucket, key, output_bucket, output_key)
            results.append(message)

        except Exception as e:
            error_message = {
                "status": "ERROR",
                "error": str(e),
                "traceback": traceback.format_exc(),
                "record": record,
                "request_id": getattr(context, "aws_request_id", None),
            }
            logger.error("Processing failed: %s", json.dumps(error_message))
            publish_notification("Image processing failed", error_message)
            results.append(error_message)

    return {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": "Processing complete",
                "results": results,
            }
        ),
    }


def extract_s3_info(record: dict) -> Tuple[Optional[str], Optional[str]]:
    s3_info = record.get("s3", {})
    bucket = s3_info.get("bucket", {}).get("name")
    key = s3_info.get("object", {}).get("key")
    return bucket, key


def read_s3_object(bucket: str, key: str):
    try:
        response = s3.get_object(Bucket=bucket, Key=key)
        body = response["Body"].read()
        metadata = {
            "ContentType": response.get("ContentType", "application/octet-stream"),
            "Metadata": response.get("Metadata", {}),
        }
        logger.info("Read %s bytes from s3://%s/%s", len(body), bucket, key)
        return body, metadata
    except ClientError as e:
        logger.exception("Failed to read s3://%s/%s", bucket, key)
        raise e


def process_image(image_bytes: bytes) -> bytes:
    logger.info("Processing image bytes of length: %s", len(image_bytes))
    return image_bytes


def build_output_key(input_key: str) -> str:
    filename = input_key.split("/")[-1]
    return f"{OUTPUT_PREFIX}{filename}"


def write_s3_object(bucket: str, key: str, body: bytes, source_bucket: str, source_key: str, source_metadata: dict):
    try:
        extra_metadata = {
            "source-bucket": source_bucket,
            "source-key": source_key,
            "processed-by": "aws-lambda-image-processor",
        }
        merged_metadata = {}
        merged_metadata.update(source_metadata.get("Metadata", {}))
        merged_metadata.update(extra_metadata)

        s3.put_object(
            Bucket=bucket,
            Key=key,
            Body=body,
            ContentType=source_metadata.get("ContentType", "application/octet-stream"),
            Metadata=merged_metadata,
        )
        logger.info("Wrote %s bytes to s3://%s/%s", len(body), bucket, key)
    except ClientError as e:
        logger.exception("Failed to write s3://%s/%s", bucket, key)
        raise e


def publish_notification(subject: str, message: dict):
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not set. Skipping notification. Subject=%s Message=%s", subject, json.dumps(message))
        return

    try:
        sns.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],
            Message=json.dumps(message, default=str),
        )
        logger.info("Published SNS notification to %s", SNS_TOPIC_ARN)
    except ClientError:
        logger.exception("Failed to publish SNS notification")
        raise